#include <stdio.h>
#include <string.h>

void getSubsequences(char *s) {
    int n = strlen(s);
    int total = 1 << n;
    for (int mask = 0; mask < total; mask++) {
        char subseq[100];
        subseq[0] = '\0';
        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                strcat(subseq, &s[i]);
            }
        }
        printf("%s\n", subseq);
    }
}

int main() {
    char s[100];
    printf("Enter a string: ");
    scanf("%s", s);
    getSubsequences(s);
    return 0;
}

